const express = require('express');
const http = require('http');
const crypto = require('crypto');
const { Server } = require('socket.io');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

app.use(express.json());

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24;
const MAX_USERNAME_LEN = 32;
const MAX_SCORE = Number.MAX_SAFE_INTEGER;

const users = new Map();
const sessions = new Map();
const leaderboard = new Map();

function now() {
  return Date.now();
}

function generateId(bytes = 24) {
  return crypto.randomBytes(bytes).toString('hex');
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const trimmed = username.trim();
  if (!trimmed || trimmed.length > MAX_USERNAME_LEN) return null;
  if (!/^[a-zA-Z0-9_\-\.]+$/.test(trimmed)) return null;
  return trimmed;
}

function sanitizeScore(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return null;
  if (n < 0 || n > MAX_SCORE) return null;
  return Math.floor(n);
}

function createSession(username) {
  const sessionId = generateId();
  const expiresAt = now() + SESSION_TTL_MS;
  sessions.set(sessionId, {
    sessionId,
    username,
    createdAt: now(),
    expiresAt
  });
  return { sessionId, expiresAt };
}

function getSession(sessionId) {
  const session = sessions.get(sessionId);
  if (!session) return null;
  if (session.expiresAt <= now()) {
    sessions.delete(sessionId);
    return null;
  }
  return session;
}

function touchSession(sessionId) {
  const session = sessions.get(sessionId);
  if (!session) return null;
  session.expiresAt = now() + SESSION_TTL_MS;
  return session;
}

function upsertUser(username) {
  if (!users.has(username)) {
    users.set(username, {
      username,
      createdAt: now(),
      lastSeenAt: now(),
      highScore: 0
    });
  } else {
    users.get(username).lastSeenAt = now();
  }
  return users.get(username);
}

function updateLeaderboard(username, score) {
  const current = leaderboard.get(username) || 0;
  if (score > current) leaderboard.set(username, score);
  const user = upsertUser(username);
  if (score > user.highScore) user.highScore = score;
}

function getTopLeaderboard(limit = 10) {
  return [...leaderboard.entries()]
    .map(([username, score]) => ({ username, score }))
    .sort((a, b) => b.score - a.score || a.username.localeCompare(b.username))
    .slice(0, limit);
}

function cleanupExpiredSessions() {
  const t = now();
  for (const [sessionId, session] of sessions.entries()) {
    if (session.expiresAt <= t) sessions.delete(sessionId);
  }
}

setInterval(cleanupExpiredSessions, 60 * 1000).unref();

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.post('/auth/login', (req, res) => {
  const username = sanitizeUsername(req.body?.username);
  if (!username) {
    return res.status(400).json({ error: 'Invalid username' });
  }

  upsertUser(username);
  const { sessionId, expiresAt } = createSession(username);

  res.json({
    username,
    sessionId,
    expiresAt
  });
});

app.post('/auth/logout', (req, res) => {
  const sessionId = typeof req.body?.sessionId === 'string' ? req.body.sessionId : null;
  if (sessionId && sessions.has(sessionId)) {
    sessions.delete(sessionId);
  }
  res.json({ ok: true });
});

app.get('/leaderboard', (req, res) => {
  res.json({
    top: getTopLeaderboard(50)
  });
});

io.use((socket, next) => {
  const sessionId = socket.handshake.auth?.sessionId || socket.handshake.query?.sessionId;
  if (typeof sessionId !== 'string') {
    return next(new Error('Authentication required'));
  }
  const session = getSession(sessionId);
  if (!session) {
    return next(new Error('Invalid or expired session'));
  }
  socket.data.sessionId = session.sessionId;
  socket.data.username = session.username;
  touchSession(session.sessionId);
  return next();
});

io.on('connection', (socket) => {
  const username = socket.data.username;

  socket.emit('authenticated', {
    username,
    sessionId: socket.data.sessionId
  });

  socket.on('player:move', (payload) => {
    const session = getSession(socket.data.sessionId);
    if (!session) {
      return socket.emit('error', { error: 'Session expired' });
    }

    const move = payload?.move;
    const score = sanitizeScore(payload?.score);

    if (typeof move !== 'string' || !move.trim()) {
      return socket.emit('error', { error: 'Invalid move' });
    }

    if (score === null) {
      return socket.emit('error', { error: 'Invalid score' });
    }

    touchSession(session.sessionId);
    updateLeaderboard(session.username, score);

    io.emit('leaderboard:update', {
      username: session.username,
      score,
      top: getTopLeaderboard(10)
    });

    socket.emit('move:accepted', {
      move,
      score
    });
  });

  socket.on('score:update', (payload) => {
    const session = getSession(socket.data.sessionId);
    if (!session) {
      return socket.emit('error', { error: 'Session expired' });
    }

    const score = sanitizeScore(payload?.score);
    if (score === null) {
      return socket.emit('error', { error: 'Invalid score' });
    }

    touchSession(session.sessionId);
    updateLeaderboard(session.username, score);

    io.emit('leaderboard:update', {
      username: session.username,
      score,
      top: getTopLeaderboard(10)
    });

    socket.emit('score:accepted', {
      username: session.username,
      score
    });
  });

  socket.on('disconnect', () => {
    const session = sessions.get(socket.data.sessionId);
    if (session) touchSession(session.sessionId);
  });
});

